                    doc_coverage = 'Unknown'
            else:
                doc_coverage = 'Unknown'

        # Validate any existing doc_coverage value and reject invalid ones
        if isinstance(doc_coverage, str):
            if '12690' in doc_coverage or 'Unknown' not in doc_coverage:
